const response = $input.first().json;
const text = response.candidates[0].content.parts[0].text;
const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const extracted = JSON.parse(cleaned);
return [{ json: { extractedData: extracted } }];

const items = $input.all();
let allText = '';
for (const item of items) {
  const row = item.json;
  const values = Object.entries(row)
    .filter(([key, val]) => val !== null && val !== undefined && String(val).trim() !== '')
    .map(([key, val]) => `${key}: ${val}`)
    .join(' | ');
  if (values.trim()) {
    allText += values + '\n';
  }
}
let firmHint = '';
const lower = allText.toLowerCase();
if (lower.includes('jll') || lower.includes('jones lang lasalle')) {
  firmHint = 'This appears to be a JLL-format RFP. JLL typically places scope, evaluation criteria, and submission requirements on separate tabs.';
} else if (lower.includes('gardiner') || lower.includes('g&t')) {
  firmHint = 'This appears to be a Gardiner & Theobald-format RFP. G&T uses structured requirement matrices across tabs.';
} else if (lower.includes('vva')) {
  firmHint = 'This appears to be a VVA-format RFP. VVA spreads fabrication scope, vendor requirements, and evaluation across multiple tabs.';
}
return [{
  json: {
    prompt: `Extract structured data from this RFP spreadsheet. ${firmHint}
IMPORTANT: Only the first sheet of this multi-tab spreadsheet is shown. Based on the project overview data visible, infer likely evaluation criteria, required certifications, and scope details that would typically accompany this type of RFP from this PM firm.
Return ONLY valid JSON with no markdown formatting, no code fences, and no extra text. Use this exact structure: {"issuer": "", "projectTitle": "", "submissionDeadline": "", "scopeOfWork": "", "evaluationCriteria": "", "requiredCertifications": "", "budgetRange": "", "serviceLine": "", "requiredSections": [], "keyRequirements": []}

For serviceLine, choose exactly one of these four values using these rules:
- "Design + Fabrication": RFP requests BOTH design/wayfinding services AND fabrication, manufacturing, or installation of signs
- "Design Only": RFP requests design or wayfinding services only, with NO mention of fabrication or manufacturing
- "Fabrication Only": RFP requests manufacturing or building of signs only, with no design work
- "Fabrication + Installation": RFP requests fabrication AND installation but NO design services
When in doubt, look for words like "fabrication", "manufacturing", "production", "installation of signs" — if present alongside design, use "Design + Fabrication".

Spreadsheet content:
${allText}`
  }
}];

const input = $input.first().json;
const text = input.content?.parts?.[0]?.text || input.text || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const parsed = JSON.parse(cleaned);

// Wrap in extractedData to match PDF path structure
return [{ json: { extractedData: parsed } }];

let serviceLine = '';
try {
  serviceLine = $('Extract Gemini Response').first().json.extractedData?.serviceLine || '';
} catch (e) {}
if (!serviceLine) {
  try {
    serviceLine = $('Extract Excel Response').first().json.extractedData?.serviceLine || '';
  } catch (e) {}
}
if (!serviceLine) {
  try {
    serviceLine = $('Extract Word Response').first().json.extractedData?.serviceLine || '';
  } catch (e) {}
}

// Normalize service line variations
// Use 'install' and 'fab' as substrings so we match "Install", "Installation",
// "Fab", "Fabrication", "Fab & Install", etc.
const normalized = serviceLine.trim().toLowerCase();
const hasDesign  = normalized.includes('design');
const hasFab     = normalized.includes('fab');
const hasInstall = normalized.includes('install');

if (hasDesign && hasFab) {
  serviceLine = 'Design + Fabrication';
} else if (hasFab && hasInstall) {
  serviceLine = 'Fabrication + Installation';
} else if (hasFab) {
  serviceLine = 'Fabrication Only';
} else if (hasDesign) {
  serviceLine = 'Design Only';
}

return [{ json: { serviceLine } }];

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = binaryData.toString('base64');
return [{ json: { base64Data: base64, mimeType: "application/pdf" } }];

const items = $input.all();

const parseDeadline = (raw) => {
  if (!raw) return '';
  let s = String(raw).trim();

  // Strip everything after "by", "at", "@", or a comma+time
  s = s.replace(/\s+(by|at|@)\s+.*$/i, '');
  s = s.replace(/,\s*\d{1,2}:\d{2}.*$/i, '');
  s = s.replace(/\s+\d{1,2}:\d{2}\s*(am|pm)?.*$/i, '');

  // Try native Date parse
  const d = new Date(s);
  if (!isNaN(d.getTime())) {
    return d.toISOString().split('T')[0]; // YYYY-MM-DD
  }
  return '';
};

return items.map(item => {
  const extracted = item.json.extractedData || {};
  const rawDeadline = extracted.submissionDeadline || '';
  const normalizedDeadline = parseDeadline(rawDeadline);

  return {
    json: {
      ...item.json,
      extractedData: {
        ...extracted,
        submissionDeadline: normalizedDeadline,          // clean ISO date for Airtable
        submissionDeadlineRaw: rawDeadline,              // original string preserved
      },
      submissionDeadlineDate: normalizedDeadline,
    }
  };
});

/**
 * n8n Code Node: "Assemble Prompt v3"
 *
 * Builds the full GPT-4o prompt for proposal generation.
 * v3 additions:
 *   - Supplementary context section (from supporting documents)
 *   - Cover letter generation instructions (prepended to proposal)
 *
 * Token budget: ~25K input to stay under 30K TPM limit.
 * Allocation: system ~500, RFP ~2K, supplementary ~3K, Airtable ~8K,
 *             instructions ~4K, cover letter ~500 = ~18K input, ~10K output.
 */

const merged = $input.first().json;

// ---- Helper: find specific boilerplate entries ----
function findBP(name) {
  const bp = merged.boilerplate || [];
  const match = bp.find(b => b.section && b.section.toLowerCase().includes(name.toLowerCase()));
  return match ? match.content : '';
}

// ---- Truncation helpers (same as v2) ----
function truncate(str, maxChars) {
  if (!str) return '';
  str = String(str);
  return str.length > maxChars ? str.substring(0, maxChars) + '...' : str;
}

function capList(arr, max) {
  return (arr || []).slice(0, max);
}

// ---- Extract key data ----
const rfp = merged.extractedData || {};
const serviceLine = merged.serviceLine || 'Design + Fabrication';

// ---- Build team bios section (capped at 5, truncated) ----
const teamSection = capList(merged.teamBios, 5).map(t =>
  `- ${t.name}, ${t.title}${t.role ? ' (' + t.role + ')' : ''}${t.certifications ? ' [' + t.certifications + ']' : ''}\n  Bio: ${truncate(t.bio, 400)}`
).join('\n');

// ---- Build references section (capped at 5) ----
const refsSection = capList(merged.references, 5).map(r =>
  `- ${r.client} — ${r.project}${r.year ? ' (' + r.year + ')' : ''}${r.tier ? ' [' + r.tier + ']' : ''}\n  ${truncate(r.description, 300)}\n  Contact: ${r.contactName}${r.contactEmail ? ', ' + r.contactEmail : ''}${r.contactPhone ? ', ' + r.contactPhone : ''}`
).join('\n');

// ---- Build portfolio section (capped at 5) ----
const portfolioSection = capList(merged.portfolio, 5).map(p => {
  let entry = `- ${p.project}${p.client ? ' (Client: ' + p.client + ')' : ''}`;
  if (p.location) entry += `\n  Location: ${p.location}`;
  if (p.gc) entry += ` | GC: ${p.gc}`;
  if (p.projectSize) entry += `\n  Project Size: ${p.projectSize}`;
  if (p.scopeOfServices) entry += `\n  Scope of Services: ${p.scopeOfServices}`;
  if (p.designValue) entry += ` | Design Value: ${p.designValue}`;
  if (p.fabricationValue) entry += ` | Fabrication Value: ${p.fabricationValue}`;
  if (p.status) entry += `\n  Status: ${p.status}`;
  entry += `\n  ${truncate(p.summary, 300)}`;
  return entry;
}).join('\n');

// ---- Build schedule section ----
const scheduleSection = capList(merged.schedules, 3).map(s =>
  `Template: ${s.template}\nPhases: ${truncate(s.phases, 500)}\nDuration: ${s.totalDuration || 'TBD'}`
).join('\n---\n');

// ---- Build rates section ----
const ratesSection = capList(merged.rates, 10).map(r =>
  `- ${r.role}: ${r.rate}${r.notes ? ' (' + r.notes + ')' : ''}`
).join('\n');

// ---- Boilerplate entries (only the 4 we need, same as v2) ----
const firmOverviewBP = findBP('firm overview') || findBP('overview');
const missionBP = findBP('mission');
const firmHistoryBP = findBP('firm history') || findBP('history');
const disputesBP = findBP('dispute');

// ---- v3: Build supplementary context section ----
let supplementarySection = '';
if (merged.hasSupplementary && merged.supplementarySummaries.length > 0) {
  supplementarySection = '\n=== SUPPLEMENTARY DOCUMENTS ===\n';
  supplementarySection += 'The following documents were included with the RFP package. Use this context to make the proposal more specific, informed, and tailored:\n\n';

  for (const summary of merged.supplementarySummaries) {
    supplementarySection += `[File: ${summary.fileName}] (${summary.fileType})\n`;
    supplementarySection += `Summary: ${truncate(summary.summary, 500)}\n`;

    if (summary.relevantDetails && summary.relevantDetails.length > 0) {
      supplementarySection += `Key details:\n`;
      for (const detail of summary.relevantDetails.slice(0, 5)) {
        supplementarySection += `  - ${truncate(detail, 200)}\n`;
      }
    }

    if (summary.budgetInfo && summary.budgetInfo !== 'null') {
      supplementarySection += `Budget info: ${truncate(summary.budgetInfo, 300)}\n`;
    }
    if (summary.siteInfo && summary.siteInfo !== 'null') {
      supplementarySection += `Site info: ${truncate(summary.siteInfo, 300)}\n`;
    }
    if (summary.technicalSpecs && summary.technicalSpecs !== 'null') {
      supplementarySection += `Technical specs: ${truncate(summary.technicalSpecs, 300)}\n`;
    }
    if (summary.scheduleInfo && summary.scheduleInfo !== 'null') {
      supplementarySection += `Schedule info: ${truncate(summary.scheduleInfo, 300)}\n`;
    }

    supplementarySection += '\n';
  }
}

// ---- Assemble the full prompt ----
const prompt = `You are a proposal writer for Outer Image LLC, a Brooklyn-based WBE-certified signage design, fabrication, and implementation studio located at 226 42nd Street, Brooklyn, NY 11232. Phone: 212.661.2124. Website: www.outerimage.com.

Generate a complete proposal response for the following RFP. The proposal MUST begin with a Cover Letter, followed by the standard 7-section proposal template.

=== RFP DATA ===
Issuer: ${rfp.issuer || 'Unknown'}
Project Title: ${rfp.projectTitle || 'Unknown'}
Submission Deadline: ${rfp.submissionDeadline || 'TBD'}
Service Line: ${serviceLine}
Scope of Work: ${truncate(rfp.scopeOfWork, 1500)}
Evaluation Criteria: ${truncate(rfp.evaluationCriteria, 500)}
Required Certifications: ${rfp.requiredCertifications || 'None specified'}
Budget Range: ${rfp.budgetRange || 'Not specified'}
Key Requirements: ${Array.isArray(rfp.keyRequirements) ? rfp.keyRequirements.join('; ') : (rfp.keyRequirements || 'None specified')}
${supplementarySection}
=== AIRTABLE CONTENT LIBRARY ===

--- TEAM BIOS ---
${teamSection || 'No team bios available.'}

--- CLIENT REFERENCES ---
${refsSection || 'No references available.'}

--- PORTFOLIO PROJECTS ---
${portfolioSection || 'No portfolio projects available.'}

--- PROJECT SCHEDULE TEMPLATES ---
${scheduleSection || 'No schedule templates available.'}

--- RATE SCHEDULES ---
${ratesSection || 'No rate schedules available.'}

--- BOILERPLATE: FIRM OVERVIEW ---
${truncate(firmOverviewBP, 1000) || 'Not available.'}

--- BOILERPLATE: MISSION ---
${truncate(missionBP, 500) || 'Not available.'}

--- BOILERPLATE: FIRM HISTORY ---
${truncate(firmHistoryBP, 500) || 'Not available.'}

--- BOILERPLATE: DISPUTES ---
${truncate(disputesBP, 300) || 'Not available.'}

=== PROPOSAL INSTRUCTIONS ===

Generate the proposal in markdown format. Start with ## Cover Letter, then continue with the standard sections.

## Cover Letter
Write a professional cover letter. Include:
- The current date (use the submission deadline date if available, otherwise today's date)
- Addressed to the RFP issuer organization
- Reference the project title and any RFP number if available
- Opening paragraph: Express Outer Image's enthusiasm and interest in the project
- Middle paragraph: Highlight Outer Image's most relevant qualifications — WBE certification, Brooklyn-based studio, and 2-3 specific projects from the portfolio that relate to this RFP's sector. Reference the supplementary documents if they reveal specific site conditions or requirements
- Closing paragraph: Mention the key team members who would lead this project, express confidence, and provide contact information
- Sign off: "Sincerely," followed by the lead team member's name and title, then "Outer Image LLC"
- Keep the cover letter to approximately one page (300-400 words)

## 1. Firm Overview
Write exactly 3 paragraphs:
- Paragraph 1: Use the Firm Overview boilerplate as the foundation (adapt, don't copy verbatim)
- Paragraph 2: Expand on Outer Image's capabilities relevant to this RFP's service line (${serviceLine})
- Paragraph 3: ONE closing paragraph that references ONLY projects from the client's sector. If the client is corporate/commercial, reference only corporate projects. If healthcare, only healthcare. If government/municipal, only government projects. Do NOT mix sectors.

## 2. Value to [Client Name]
Write 2-3 paragraphs tailored specifically to the RFP issuer explaining why Outer Image is uniquely positioned for this project. Reference specific details from the RFP scope of work and any supplementary documents. Address evaluation criteria directly.

## 3. Corporate Information

### 3.21 Firm History
Use the Firm History boilerplate. Keep to 1 paragraph.

### 3.22 Office Location
226 42nd Street, Brooklyn, NY 11232. Mention proximity/accessibility to the project location if known from the RFP or supplementary documents.

### 3.23 Project Team
List the team members from the bios provided. For each: Name, Title, and a 2-sentence summary of their relevant experience. Match team to the service line.

### 3.24 Disputes
Use the Disputes boilerplate. If it says "none", state clearly: "Outer Image LLC has no record of disputes, litigation, or contract terminations."

### 3.25 Mission
Use the Mission boilerplate. Keep to 1 paragraph.

## 4. Project Approach

### 4.26 Unique Systems
Describe Outer Image's proprietary approach to signage systems for this project type.

### 4.27 Wayfinding Design
Explain the wayfinding methodology. If supplementary documents include site plans or maps, reference specific site conditions.

### 4.28 Stakeholder Input
Describe the stakeholder engagement process.

### 4.29 Cost Management
Explain cost control approach. If budget information is available from the RFP or supplementary docs, reference it.

### 4.30 Coordination
Describe coordination with other contractors/consultants. If a GC or other parties are mentioned in supplementary docs, reference them.

### 4.31 Quality Assurance
Describe QA/QC procedures.

### 4.32 CAD/Revit Deliverables
List standard deliverable formats.

### 4.33 Internal Structure
Describe the project management structure.

### 4.34 Proposed Fee
Reference the rate schedule data. Present as a summary, not a line-item breakdown.

## 5.2 Proposed Schedule
Create a markdown table with columns: | Activity | Days to Complete | Anticipated Dates |
Base this on the schedule template data. Include at minimum: Design Development, Client Review, Fabrication Drawings, Fabrication, Installation.

## 5.03 Project Experience
List up to 5 relevant projects from the portfolio. For each project, use this EXACT compact format with NO blank lines between fields within a project:
**[Project Name]**
Client: [Client Name]
Location: [Location]
GC: [General Contractor]
Status: [Status]
Project Size: [Size]
Scope of Services: [Scope]
Design Value: [Value]
Fabrication Value: [Value]
[1-2 sentence description]

Separate each project with ONE blank line.

=== FORMATTING RULES ===
1. Use markdown headings: ## for main sections, ### for subsections
2. Do NOT wrap the output in code fences (\`\`\`markdown or \`\`\`)
3. Start the output with ## Cover Letter
4. Use markdown table syntax for section 5.2 (pipes and dashes)
5. Bold text with **double asterisks**
6. No bullet points in section 5.03 — use the compact format specified above
7. Keep consecutive lines in section 5.03 with no blank lines between fields within a project
8. Reference supplementary document details naturally — do NOT just list them
9. The cover letter should feel personal and specific, not generic
10. Total output should be approximately 3,000-4,000 words`;

return [{
  json: {
    prompt,
    model: 'gpt-4o',
    maxTokens: 10000,
    temperature: 0.7,
  }
}];

/**
 * n8n Code Node: "Merge All Content v3"
 *
 * Combines:
 *   - Primary RFP extracted data (from Gemini Parse PDF)
 *   - Airtable content (team bios, references, portfolio, etc.)
 *   - Supplementary file summaries (new in v3)
 *
 * This is the v3 version of v2's "Merge Content1" node.
 * Same Airtable field mappings, plus supplementary context.
 */

// ---- Primary RFP data (same as v2) ----
let extractedData = {};
try {
  extractedData = $('Extract Gemini Response').first().json.extractedData || {};
} catch (e) {}

let serviceLine = '';
try {
  serviceLine = $('Set Service Line').first().json.serviceLine || '';
} catch (e) {}

// ---- Airtable content (same as v2) ----
let teamBios = [];
try {
  teamBios = $('Fetch Team Bios').all().map(i => ({
    name: i.json.Name || i.json['Name'] || '',
    title: i.json.Title || i.json['Title'] || '',
    role: i.json.Role || i.json['Role'] || '',
    bio: i.json['Bio (Short)'] || i.json['Bio (Full)'] || '',
    certifications: i.json.Certifications || i.json['Certifications'] || '',
  }));
} catch (e) {}

let references = [];
try {
  references = $('Fetch Client References').all().map(i => ({
    client: i.json['Client Name'] || '',
    project: i.json['Project Name'] || '',
    description: i.json['Project Description'] || '',
    contactName: i.json['Contact Name'] || '',
    contactEmail: i.json['Contact Email'] || i.json['Contact Info'] || '',
    contactPhone: i.json['Contact Phone'] || '',
    year: i.json['Year'] || '',
    tier: i.json['Client Tier'] || '',
  }));
} catch (e) {}

let portfolio = [];
try {
  portfolio = $('Fetch Portfolio').all().map(i => ({
    project: i.json['Project Name'] || '',
    client: i.json['Client'] || i.json['Client Name'] || '',
    summary: i.json['Summary'] || '',
    location: i.json['Location'] || '',
    gc: i.json['GC'] || i.json['General Contractor'] || '',
    projectSize: i.json['Project Size'] || '',
    scopeOfServices: i.json['Scope of Services'] || '',
    designValue: i.json['Design Value'] || '',
    fabricationValue: i.json['Fabrication Value'] || '',
    status: i.json['Status'] || '',
    completionDate: i.json['Completion Date'] || '',
    tier: i.json['Client Tier'] || '',
    tags: i.json['Project Type Tags'] || '',
  }));
} catch (e) {}

let boilerplate = [];
try {
  boilerplate = $('Fetch Boilerplate Content').all().map(i => ({
    section: i.json['Section Name'] || '',
    content: i.json['Content'] || '',
  }));
} catch (e) {}

let schedules = [];
try {
  schedules = $('Fetch Project Schedules').all().map(i => ({
    template: i.json['Template Name'] || '',
    phases: i.json['Phases'] || '',
    totalDuration: i.json['Total Duration'] || '',
    notes: i.json['Notes'] || '',
  }));
} catch (e) {}

let rates = [];
try {
  rates = $('Fetch Rate Schedules').all().map(i => ({
    role: i.json['Role / Line Item'] || '',
    rate: i.json['Rate'] || '',
    notes: i.json['Notes'] || '',
  }));
} catch (e) {}

// ---- v3: Supplementary file summaries ----
let supplementarySummaries = [];
try {
  const summaryData = $('Collect Supplementary Summaries').first().json;
  supplementarySummaries = summaryData.supplementarySummaries || [];
} catch (e) {}

// ---- Assemble merged payload ----
return [{
  json: {
    // RFP data
    extractedData,
    serviceLine,

    // Airtable content
    teamBios,
    references,
    portfolio,
    boilerplate,
    schedules,
    rates,

    // v3: Supplementary context
    supplementarySummaries,
    hasSupplementary: supplementarySummaries.length > 0,

    // Metadata
    version: '3.0',
  }
}];

const input = $input.first().json;
const text = input.content?.parts?.[0]?.text || input.text || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const parsed = JSON.parse(cleaned);

return [{ json: { extractedData: parsed } }];

const body = $('Webhook (Trigger)').first().json.body;
const extractedText = body.extractedText || '';
const prompt = `Extract structured data from this RFP document. Return ONLY valid JSON with no markdown formatting, no code fences, and no extra text. Use this exact structure: {"issuer": "", "projectTitle": "", "submissionDeadline": "", "scopeOfWork": "", "evaluationCriteria": "", "requiredCertifications": "", "budgetRange": "", "serviceLine": "", "requiredSections": [], "keyRequirements": []}

For serviceLine, choose exactly one of these four values using these rules:
- "Design + Fabrication": RFP requests BOTH design/wayfinding services AND fabrication, manufacturing, or installation of signs
- "Design Only": RFP requests design or wayfinding services only, with NO mention of fabrication or manufacturing
- "Fabrication Only": RFP requests manufacturing or building of signs only, with no design work
- "Fabrication + Installation": RFP requests fabrication AND installation but NO design services
When in doubt, look for words like "fabrication", "manufacturing", "production", "installation of signs" — if present alongside design, use "Design + Fabrication".

Document content:
${extractedText}`;

return [{
  json: {
    prompt,
    extractedText,
    fileName: body.fileName
  }
}];

/**
 * n8n Code Node: "Parse Metadata"
 *
 * Receives the webhook payload from the v3 portal.
 * Separates primary RFP info from supplementary files.
 * Outputs structured data for downstream nodes.
 *
 * Place this node immediately after the Webhook trigger.
 */

const items = $input.all();
const item = items[0].json;

// Primary RFP info (same fields as v2)
const primaryRfp = {
  recordId: item.recordId,
  fileUrl: item.fileUrl,
  fileName: item.fileName,
  fileType: item.fileType,
  callbackUrl: item.callbackUrl,
  extractedText: item.extractedText || null,
  triggeredAt: item.triggeredAt,
};

// v3: Supplementary files
const supplementaryFiles = item.supplementaryFiles || [];
const fileCount = item.fileCount || 1;
const version = item.version || "2.0";

// Prioritize supplementary files for processing:
// PDFs and spreadsheets first (most useful context), then documents, then images
const priorityOrder = { pdf: 1, spreadsheet: 2, document: 3, image: 4, other: 5 };
const sortedSupplementary = [...supplementaryFiles].sort(
  (a, b) => (priorityOrder[a.fileType] || 5) - (priorityOrder[b.fileType] || 5)
);

// Cap at 5 supplementary files to stay within token budget
const cappedSupplementary = sortedSupplementary.slice(0, 5);

return [{
  json: {
    primaryRfp,
    supplementaryFiles: cappedSupplementary,
    supplementaryCount: supplementaryFiles.length,
    processedCount: cappedSupplementary.length,
    skippedCount: Math.max(0, supplementaryFiles.length - 5),
    fileCount,
    version,
    hasSupplementary: cappedSupplementary.length > 0,
  }
}];

/**
 * n8n Code Node: "Process Supplementary Files"
 *
 * Takes the list of supplementary files from Parse Metadata
 * and outputs one item per file for the Gemini summarization loop.
 *
 * Place this node after "Parse Metadata", connected to a Loop Over Items
 * that feeds into the Gemini Summarize node.
 *
 * If there are no supplementary files, outputs an empty array
 * so the downstream merge still works.
 */

const metadata = $('Parse Metadata').first().json;
const supplementaryFiles = metadata.supplementaryFiles || [];

if (supplementaryFiles.length === 0) {
  // No supplementary files — output a single item with empty context
  return [{
    json: {
      hasFiles: false,
      supplementarySummaries: [],
    }
  }];
}

// Output one item per supplementary file for the loop
return supplementaryFiles.map((file, index) => ({
  json: {
    hasFiles: true,
    fileIndex: index,
    fileName: file.name,
    fileType: file.fileType,
    fileUrl: file.url,
    mimeType: file.type,
    fileSize: file.size,
  }
}));

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = binaryData.toString('base64');
const mimeType = $input.first().binary.data.mimeType || 'application/octet-stream';
const loopItem = $('Loop Over Items').first().json;

return [{
  json: {
    base64Data: base64,
    mimeType,
    fileName: loopItem.fileName || 'supplementary',
    fileType: loopItem.fileType || 'other',
  }
}];

parameters.jsonBody:
={
  "contents": [{
    "parts": [
      {
        "inline_data": {
          "mime_type": "{{ $json.mimeType }}",
          "data": "{{ $json.base64Data }}"
        }
